 47	import { Trans } from 'react-i18next';
 48	import {
 49	  Checkbox,
 50	  Grid,
 51	  GridItem,
 52	  Form,
 53	  FormGroup,
 54	  Text,
 55	  Label,
 56	  TextVariants,
 57	  TextContent,
 58	  TextInput,
 59	} from '@patternfly/react-core';
 60	import { ValidationMessage } from '../../../utils/common-odf-install-el';
 61	import { ErrorHandler } from '../../error-handler';
 62	import { WizardDispatch, WizardNodeState, WizardState } from '../../reducer';
 63	import { SelectNodesTable } from '../../select-nodes-table/select-nodes-table';
 64	import { CapacityAutoScaling } from './capacity-autoscaling';
 65	import ConfigurePerformance, {
 66	  PerformanceHeaderText,
 67	  ProfileRequirementsText,
 68	} from './configure-performance';
 69	import { SelectedNodesTable } from './selected-nodes-table';
 70	import { StretchCluster } from './stretch-cluster';
 71	import { useVolumeTypeValidation } from './useVolumeTypeValidation';
 72	import './capacity-and-nodes.scss';
 73	
 74	const onResourceProfileChange = _.curry(
 75	  (dispatch: WizardDispatch, newProfile: ResourceProfile): void => {
 76	    dispatch({
 77	      type: 'capacityAndNodes/setResourceProfile',
 78	      payload: newProfile,
 79	    });
 80	  }
 81	);
