 83	const SelectNodesText: React.FC<SelectNodesTextProps> = React.memo(
 84	  ({ text }) => {
 85	    const { t } = useCustomTranslation();
 86	
 87	    // ToDo (epic 4422): Use StorageSystem namespace once we support multiple internal clusters
 88	    const label = `cluster.ocs.openshift.io/${DEFAULT_STORAGE_NAMESPACE}=""`;
 89	    return (
 90	      <TextContent>
 91	        <Text>{text}</Text>
 92	        <Text>
 93	          <Trans t={t as any} ns="plugin__odf-console">
 94	            If not labeled, the selected nodes are labeled{' '}
 95	            <Label color="blue">{{ label }}</Label> to make them target hosts
 96	            for Data Foundation
 97	            {/* eslint-disable react/no-unescaped-entities */}'s components.
 98	          </Trans>
 99	        </Text>
100	      </TextContent>
101	    );
102	  }
103	);
104	SelectNodesText.displayName = 'SelectNodesText';
105	
106	type SelectNodesTextProps = {
107	  text: JSX.Element;
108	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
109	};
110	
111	const EnableTaintNodes: React.FC<EnableTaintNodesProps> = ({
112	  dispatch,
113	  enableTaint,
114	}) => {
115	  const { t } = useCustomTranslation();
116	
117	  return (
118	    <Checkbox
119	      label={t('Taint nodes')}
120	      description={t(
121	        'Selected nodes will be dedicated to Data Foundation use only'
122	      )}
123	      className="odf-capacity-and-nodes__taint-checkbox"
124	      id="taint-nodes"
125	      data-checked-state={enableTaint}
126	      isChecked={enableTaint}
127	      onChange={() =>
128	        dispatch({
129	          type: 'capacityAndNodes/enableTaint',
130	          payload: !enableTaint,
131	        })
132	      }
133	    />
134	  );
135	};
136	
137	type EnableTaintNodesProps = {
138	  dispatch: WizardDispatch;
139	  enableTaint: WizardState['capacityAndNodes']['enableTaint'];
140	};
141	
142	type SelectCapacityAndNodesProps = {
143	  dispatch: WizardDispatch;
144	  capacity: WizardState['capacityAndNodes']['capacity'];
145	  nodes: WizardState['nodes'];
146	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
147	};
148	
149	const SelectCapacityAndNodes: React.FC<SelectCapacityAndNodesProps> = ({
150	  dispatch,
151	  capacity,
152	  nodes,
153	  systemNamespace,
154	}) => {
155	  const { t } = useCustomTranslation();
156	
157	  React.useEffect(() => {
158	    if (!capacity)
159	      dispatch({ type: 'capacityAndNodes/capacity', payload: '2Ti' });
160	    // eslint-disable-next-line react-hooks/exhaustive-deps
161	  }, []);
162	
163	  const onRowSelected = React.useCallback(
164	    (selectedNodes: NodeData[]) => {
165	      const nodesData = createWizardNodeState(selectedNodes);
166	      dispatch({ type: 'wizard/setNodes', payload: nodesData });
167	    },
168	    [dispatch]
169	  );
170	
171	  const replicas = getReplicasFromSelectedNodes(nodes);
172	
173	  return (
174	    <>
175	      <TextContent>
176	        <Text component={TextVariants.h3}>{t('Select capacity')}</Text>
177	      </TextContent>
178	      <FormGroup
179	        fieldId="requested-capacity-dropdown"
180	        label={t('Requested capacity')}
181	        labelHelp={
182	          <FieldLevelHelp>{requestedCapacityTooltip(t)}</FieldLevelHelp>
183	        }
184	      >
185	        <Grid hasGutter>
186	          <GridItem span={5}>
187	            <OSDSizeDropdown
188	              id="requested-capacity-dropdown"
189	              selectedKey={capacity as string}
190	              onChange={(selectedCapacity: string) =>
191	                dispatch({
192	                  type: 'capacityAndNodes/capacity',
193	                  payload: selectedCapacity,
194	                })
195	              }
196	            />
197	          </GridItem>
198	          <GridItem span={7}>
199	            <TotalCapacityText
200	              capacity={capacity as string}
201	              replica={replicas}
202	            />
203	          </GridItem>
204	        </Grid>
205	      </FormGroup>
206	      <TextContent>
207	        <Text id="select-nodes" component={TextVariants.h3}>
208	          {t('Select nodes')}
209	        </Text>
210	      </TextContent>
211	      <Grid>
212	        <GridItem span={11}>
213	          <SelectNodesText
214	            text={t(
215	              'Select at least 3 nodes preferably in 3 different zones. It is recommended to start with at least 14 CPUs and 34 GiB per node.'
216	            )}
217	            systemNamespace={systemNamespace}
218	          />
219	        </GridItem>
220	        <GridItem span={10}>
221	          <SelectNodesTable
222	            nodes={nodes}
223	            onRowSelected={onRowSelected}
224	            systemNamespace={systemNamespace}
225	          />
226	        </GridItem>
227	      </Grid>
228	    </>
229	  );
230	};
231	
232	const SelectedCapacityAndNodes: React.FC<SelectedCapacityAndNodesProps> = ({
233	  capacity,
234	  storageClassName,
235	  enableArbiter,
236	  arbiterLocation,
237	  volumeValidationType,
238	  dispatch,
239	  nodes,
240	  systemNamespace,
241	  isLSOPreConfigured,
242	}) => {
243	  const { t } = useCustomTranslation();
244	
245	  const [pvs, pvsLoaded, pvsLoadError] =
246	    useK8sWatchResource<K8sResourceKind[]>(pvResource);
247	  const [allNodes, allNodeLoaded, allNodeLoadError] = useNodesData();
248	
249	  const [hasStrechClusterEnabled, setHasStrechClusterEnabled] =
250	    React.useState(false);
251	  const [zones, setZones] = React.useState([]);
252	
253	  const pvsBySc = React.useMemo(
254	    () => getSCAvailablePVs(pvs, storageClassName),
255	    [pvs, storageClassName]
256	  );
257	
258	  React.useEffect(() => {
259	    // Updates selected capacity
260	    if (pvsLoaded && !pvsLoadError) {
261	      const pvCapacity = calcPVsCapacity(pvsBySc);
262	      dispatch({
263	        type: 'capacityAndNodes/capacity',
264	        payload: pvCapacity,
265	      });
266	      dispatch({ type: 'capacityAndNodes/pvCount', payload: pvsBySc.length });
267	    }
268	  }, [dispatch, pvsBySc, pvsLoadError, pvsLoaded]);
269	
270	  React.useEffect(() => {
271	    // Updates selected nodes
272	    if (
273	      allNodeLoaded &&
274	      !allNodeLoadError &&
275	      allNodes.length &&
276	      pvsBySc.length
277	    ) {
278	      const pvNodes = getAssociatedNodes(pvsBySc);
279	      const filteredNodes = allNodes.filter((node) =>
280	        pvNodes.includes(node.metadata.name)
281	      );
282	      const nodesData = createWizardNodeState(filteredNodes);
283	      dispatch({ type: 'wizard/setNodes', payload: nodesData });
284	    }
285	  }, [dispatch, allNodeLoadError, allNodeLoaded, allNodes, pvsBySc]);
286	
287	  React.useEffect(() => {
288	    // Validates stretch cluster topology
289	    if (allNodes.length && nodes.length) {
290	      const allZones = getZonesFromNodesKind(allNodes);
291	      const nodesPerZoneMap: NodesPerZoneMap =
292	        getPVAssociatedNodesPerZone(nodes);
293	      const isValidStretchCluster = isValidStretchClusterTopology(
294	        nodesPerZoneMap,
295	        allZones
296	      );
297	
298	      setHasStrechClusterEnabled(isValidStretchCluster);
299	      setZones(allZones);
300	    }
301	  }, [allNodes, nodes]);
302	
303	  // Skipping validation if LSO was configured as part of the SS deployment (in the previous LVS creation wizard step), as that step already have all the required validations
304	  // These validations are needed if LSO was already configured before even starting with the SS deployment
305	  useVolumeTypeValidation(
306	    nodes,
307	    pvsBySc,
308	    volumeValidationType,
309	    dispatch,
310	    isLSOPreConfigured
311	  );
312	
313	  const onArbiterChecked = React.useCallback(
314	    (isChecked: boolean) =>
315	      dispatch({ type: 'capacityAndNodes/enableArbiter', payload: isChecked }),
316	    [dispatch]
317	  );
318	
319	  const onZonesSelect = React.useCallback(
320	    (_event, selection: string) =>
321	      dispatch({
322	        type: 'capacityAndNodes/arbiterLocation',
323	        payload: selection,
324	      }),
325	    [dispatch]
326	  );
327	
328	  return (
329	    <ErrorHandler
330	      error={pvsLoadError}
331	      loaded={
332	        pvsLoaded &&
333	        !!capacity &&
334	        volumeValidationType !== VolumeTypeValidation.UNKNOWN
335	      }
336	      loadingMessage={t(
337	        'PersistentVolumes are being provisioned on the selected nodes.'
338	      )}
339	      errorMessage={t('Error while loading PersistentVolumes.')}
340	    >
341	      <>
342	        <TextContent>
343	          <Text component={TextVariants.h3}>{t('Selected capacity')}</Text>
344	        </TextContent>
345	        <FormGroup
346	          fieldId="available-raw-capacity"
347	          label={t('Available raw capacity')}
348	        >
349	          <Grid hasGutter>
350	            <GridItem span={5}>
351	              <TextInput
352	                value={humanizeBinaryBytes(capacity).string}
353	                id="available-raw-capacity"
354	                readOnlyVariant="default"
355	              />
356	              <TextContent>
357	                <Text component={TextVariants.small}>
358	                  <Trans ns="plugin__odf-console">
359	                    The available capacity is based on all attached disks
360	                    associated with the selected{' '}
361	                    {/* eslint-disable-next-line react/no-unescaped-entities */}
362	                    StorageClass <b>{{ storageClassName }}</b>
363	                  </Trans>
364	                </Text>
365	              </TextContent>
366	              <TextContent />
367	            </GridItem>
368	            <GridItem span={7} />
369	          </Grid>
370	        </FormGroup>
371	        {hasStrechClusterEnabled && (
372	          <StretchCluster
373	            enableArbiter={enableArbiter}
374	            arbiterLocation={arbiterLocation}
375	            zones={zones}
376	            onChecked={onArbiterChecked}
377	            onSelect={onZonesSelect}
378	          />
379	        )}
380	        <TextContent>
381	          <Text id="selected-nodes" component={TextVariants.h3}>
382	            {t('Selected nodes')}
383	          </Text>
384	        </TextContent>
385	        <Grid>
386	          <GridItem span={11}>
387	            <SelectNodesText
388	              text={
389	                enableArbiter
390	                  ? attachDevicesWithArbiter(t, storageClassName)
391	                  : attachDevices(t, storageClassName)
392	              }
393	              systemNamespace={systemNamespace}
394	            />
395	          </GridItem>
396	          <GridItem span={10}>
397	            <SelectedNodesTable data={nodes} />
398	          </GridItem>
399	        </Grid>
400	      </>
401	    </ErrorHandler>
402	  );
403	};
404	
405	type SelectedCapacityAndNodesProps = {
406	  capacity: WizardState['capacityAndNodes']['capacity'];
407	  enableArbiter: WizardState['capacityAndNodes']['enableArbiter'];
408	  storageClassName: string;
409	  arbiterLocation: WizardState['capacityAndNodes']['arbiterLocation'];
410	  dispatch: WizardDispatch;
411	  nodes: WizardNodeState[];
412	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
413	  volumeValidationType: VolumeTypeValidation;
414	  isLSOPreConfigured: boolean;
415	};
416	
417	export const CapacityAndNodes: React.FC<CapacityAndNodesProps> = ({
418	  state,
419	  dispatch,
420	  storageClass,
421	  volumeSetName,
422	  nodes,
423	  systemNamespace,
424	  infraType,
425	}) => {
426	  const {
427	    capacity,
428	    capacityAutoScaling,
429	    enableArbiter,
430	    enableTaint,
431	    arbiterLocation,
432	    resourceProfile,
433	    volumeValidationType,
434	    pvCount,
435	  } = state;
436	
437	  const isNoProvisioner = storageClass.provisioner === NO_PROVISIONER;
438	  const flexibleScaling = isFlexibleScaling(
439	    nodes,
440	    isNoProvisioner,
441	    enableArbiter
442	  );
443	  const deviceSetReplica: number = getDeviceSetReplica(
444	    enableArbiter,
445	    flexibleScaling,
446	    nodes
447	  );
448	  const deviceSetCount = getDeviceSetCount(pvCount, deviceSetReplica);
449	  const osdAmount = getOsdAmount(deviceSetCount, deviceSetReplica);
450	
451	  const validations = capacityAndNodesValidate(
452	    nodes,
453	    state,
454	    isNoProvisioner,
455	    osdAmount
456	  );
457	  const onProfileChange = React.useCallback(
458	    (profile) => onResourceProfileChange(dispatch)(profile),
459	    [dispatch]
460	  );
461	
462	  // In case LSO is already configured (before SS deployment), wizard skips LVS creation step (thus, corresponding redux state should be empty)
463	  const isLSOPreConfigured = !volumeSetName;
464	
465	  const { capacityLimit, enable: enableAutoScaling } = capacityAutoScaling;
466	  const onCapacityAutoscalingChange = (_ev, checked: boolean) => {
467	    dispatch({
468	      type: 'capacityAndNodes/capacityAutoScaling',
469	      payload: { capacityLimit, enable: checked },
470	    });
471	  };
472	  const onCapacityAutoscalingSelect = (selected: string) => {
473	    dispatch({
474	      type: 'capacityAndNodes/capacityAutoScaling',
475	      payload: { capacityLimit: selected, enable: enableAutoScaling },
476	    });
477	  };
478	  return (
479	    <Form>
480	      {isNoProvisioner ? (
481	        <SelectedCapacityAndNodes
482	          storageClassName={storageClass.name || volumeSetName}
483	          enableArbiter={enableArbiter}
484	          arbiterLocation={arbiterLocation}
485	          volumeValidationType={volumeValidationType}
486	          dispatch={dispatch}
487	          nodes={nodes}
488	          capacity={capacity}
489	          systemNamespace={systemNamespace}
490	          isLSOPreConfigured={isLSOPreConfigured}
491	        />
492	      ) : (
493	        <SelectCapacityAndNodes
494	          dispatch={dispatch}
495	          capacity={capacity}
496	          nodes={nodes}
497	          systemNamespace={systemNamespace}
498	        />
499	      )}
500	      {(!isNoProvisioner || nodes.length > 0) && (
501	        <>
502	          <ConfigurePerformance
503	            onResourceProfileChange={onProfileChange}
504	            resourceProfile={resourceProfile}
505	            headerText={PerformanceHeaderText}
506	            profileRequirementsText={ProfileRequirementsText}
507	            selectedNodes={nodes}
508	            osdAmount={osdAmount}
509	          />
510	          <EnableTaintNodes dispatch={dispatch} enableTaint={enableTaint} />
511	        </>
512	      )}
513	      {isCapacityAutoScalingAllowed(infraType, resourceProfile) && (
514	        <CapacityAutoScaling
515	          capacityLimit={capacityLimit}
516	          className="pf-v6-u-w-75"
517	          enable={enableAutoScaling}
518	          onChange={onCapacityAutoscalingChange}
519	          onLimitSelect={onCapacityAutoscalingSelect}
520	          osdAmount={osdAmount}
521	          osdSize={String(capacity)}
522	        />
523	      )}
524	      {!!validations.length &&
525	        !!capacity &&
526	        validations.map((validation) => (
527	          <ValidationMessage
528	            resourceProfile={resourceProfile}
529	            volumeValidationType={volumeValidationType}
530	            osdAmount={osdAmount}
531	            key={validation}
532	            validation={validation}
533	          />
534	        ))}
535	    </Form>
536	  );
537	};
538	
539	type CapacityAndNodesProps = {
540	  state: WizardState['capacityAndNodes'];
541	  storageClass: WizardState['storageClass'];
542	  nodes: WizardState['nodes'];
543	  volumeSetName: WizardState['createLocalVolumeSet']['volumeSetName'];
544	  dispatch: WizardDispatch;
545	  infraType: InfraProviders;
546	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
547	};

